<?php
require_once '../includes/session_init.php';require_once '../database.php';if(empty($_SESSION['super_admin'])||$_SERVER['REQUEST_METHOD']!=='POST'){http_response_code(403);exit('Acesso negado.');}$id=(int)($_POST['id']??0);$tipo=$_POST['tipo']??'';if($id<=0||!in_array($tipo,['interno','externo'],true))exit('Registro inválido.');$conn=getMasterConnection();$conn->begin_transaction();
try{if($tipo==='interno'){$check=$conn->prepare("SELECT id FROM chamados_suporte WHERE id=? AND status='concluido' AND encerrado_em<=DATE_SUB(NOW(),INTERVAL 5 YEAR)");$check->bind_param('i',$id);$check->execute();if(!$check->get_result()->num_rows)throw new Exception('Registro ainda protegido pela retenção.');$s=$conn->prepare('DELETE FROM chamados_historico WHERE chamado_id=?');$s->bind_param('i',$id);$s->execute();$s=$conn->prepare('DELETE FROM chamados_suporte WHERE id=?');}else{$check=$conn->prepare("SELECT id FROM suporte_login WHERE id=? AND status IN ('resolvido','fechado') AND resolvido_em<=DATE_SUB(NOW(),INTERVAL 5 YEAR)");$check->bind_param('i',$id);$check->execute();if(!$check->get_result()->num_rows)throw new Exception('Registro ainda protegido pela retenção.');$s=$conn->prepare('DELETE FROM suporte_historico WHERE suporte_id=?');$s->bind_param('i',$id);$s->execute();$s=$conn->prepare('DELETE FROM suporte_login WHERE id=?');}$s->bind_param('i',$id);$s->execute();$conn->commit();header('Location: ../pages/admin/arquivos_suportes.php?msg=excluido');}catch(Throwable $e){$conn->rollback();http_response_code(422);echo htmlspecialchars($e->getMessage());}
